            await _autosaveTimer.DisposeAsync();
        }

        if (_interop is not null)
        {
            await _interop.DisposeAsync();
        }

        _dotNetRef?.Dispose();
    }
}

const STORAGE_KEY = 'notepad-content';
const ON_AUTOSAVE_TICK = 'OnAutosaveTick';

class NotepadBridge {
    #dotNetRef;
    #handleBeforeUnload;

    constructor(dotNetRef) {
        this.#dotNetRef = dotNetRef;
        this.#handleBeforeUnload = (e) => {
            e.preventDefault();
        };
    }

    load() {
        return localStorage.getItem(STORAGE_KEY) ?? '';
    }

    save(content) {
        localStorage.setItem(STORAGE_KEY, content);
    }

    clear() {
        localStorage.removeItem(STORAGE_KEY);
    }

    enableUnloadGuard() {
        window.addEventListener('beforeunload', this.#handleBeforeUnload);
    }

    disableUnloadGuard() {
        window.removeEventListener('beforeunload', this.#handleBeforeUnload);
    }

    dispose() {
        this.disableUnloadGuard();
    }
}

let bridge;

export function initialize(dotNetRef) {
    bridge = new NotepadBridge(dotNetRef);
    return bridge.load();
}

export function save(content) {
    bridge?.save(content);
}

export function clear() {
    bridge?.clear();
}

export function enableUnloadGuard() {
    bridge?.enableUnloadGuard();
}

export function disableUnloadGuard() {
    bridge?.disableUnloadGuard();
}

export function dispose() {
    bridge?.dispose();
    bridge = null;
}

