    internal const string DisableGuardMethod = "disableUnloadGuard";
    internal const string DisposeMethod = "dispose";

    private readonly IJSRuntime _js;
    private IJSObjectReference? _module;

    public NotepadInterop(IJSRuntime js) => _js = js;

    private async ValueTask<IJSObjectReference> GetModuleAsync()
        => _module ??= await _js.InvokeAsync<IJSObjectReference>("import", ModulePath);

    public async ValueTask<string> InitializeAsync<T>(DotNetObjectReference<T> dotNetRef) where T : class
    {
        var module = await GetModuleAsync();
        return await module.InvokeAsync<string>(InitMethod, dotNetRef);
    }

    public async ValueTask SaveAsync(string content)
    {
        var module = await GetModuleAsync();
        await module.InvokeVoidAsync(SaveMethod, content);
    }

    public async ValueTask ClearAsync()
    {
        var module = await GetModuleAsync();
        await module.InvokeVoidAsync(ClearMethod);
    }

    public async ValueTask EnableUnloadGuardAsync()
    {
        var module = await GetModuleAsync();
        await module.InvokeVoidAsync(EnableGuardMethod);
    }

    public async ValueTask DisableUnloadGuardAsync()
    {
        var module = await GetModuleAsync();
        await module.InvokeVoidAsync(DisableGuardMethod);
    }

    public async ValueTask DisposeAsync()
    {
        try
        {
            if (_module is not null)
            {
                await _module.InvokeVoidAsync(DisposeMethod);
                await _module.DisposeAsync();
            }
        }
        catch (JSDisconnectedException) { }
    }
